import React from "react";

function Filters() {
  return (
    <div style={{ padding: "20px" }}>
      <h3>Filters</h3>
      <label>
        <input type="checkbox" /> Electronics
      </label><br/>
      <label>
        <input type="checkbox" /> Clothing
      </label><br/>
      <label>
        <input type="checkbox" /> Jewelry
      </label>
    </div>
  );
}

export default Filters;
